arguments.new_str:
namespace Payments;

public interface IPaymentProcessor
{
    Task<ProcessorChargeResponse> CreateChargeAsync(string cardToken, decimal amount);
    Task<ProcessorRefundResponse> CreateRefundAsync(string chargeId);
}

public interface ITransactionRepository
{
    Task SaveTransactionAsync(Transaction transaction);
    Task<Transaction?> GetTransactionAsync(string chargeId);
    Task UpdateTransactionStatusAsync(string chargeId, TransactionStatus status);
}

public sealed class PaymentGateway
{
    private readonly IPaymentProcessor _processor;
    private readonly ITransactionRepository _repository;

    public PaymentGateway(IPaymentProcessor processor, ITransactionRepository repository)
    {
        _processor = processor ?? throw new ArgumentNullException(nameof(processor));
        _repository = repository ?? throw new ArgumentNullException(nameof(repository));
    }

    public async Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        if (string.IsNullOrWhiteSpace(cardToken))
            throw new ArgumentException("Card token is required.", nameof(cardToken));
        if (amount <= 0)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount must be positive.");
        if (amount > 999_999.99m)
            throw new ArgumentOutOfRangeException(nameof(amount), "Amount exceeds maximum allowed.");

        var response = await _processor.CreateChargeAsync(cardToken, amount);

        var transaction = new Transaction(
            response.ChargeId,
            cardToken,
            amount,
            response.Succeeded ? TransactionStatus.Charged : TransactionStatus.Failed,
            DateTime.UtcNow);

        await _repository.SaveTransactionAsync(transaction);

        return new ChargeResult(response.ChargeId, response.Succeeded);
    }

    public async Task<RefundResult> RefundAsync(string chargeId)
    {
        if (string.IsNullOrWhiteSpace(chargeId))
            throw new ArgumentException("Charge ID is required.", nameof(chargeId));

        var existing = await _repository.GetTransactionAsync(chargeId);
        if (existing is null)
            throw new InvalidOperationException($"Transaction '{chargeId}' not found.");
        if (existing.Status == TransactionStatus.Refunded)
            throw new InvalidOperationException($"Transaction '{chargeId}' is already refunded.");
        if (existing.Status != TransactionStatus.Charged)
            throw new InvalidOperationException($"Transaction '{chargeId}' is not in a refundable state.");

        var response = await _processor.CreateRefundAsync(chargeId);

        if (response.Succeeded)
            await _repository.UpdateTransactionStatusAsync(chargeId, TransactionStatus.Refunded);

        return new RefundResult(response.RefundId, response.Succeeded);
    }

    public async Task HandleWebhookAsync(WebhookEvent webhookEvent)
    {
        ArgumentNullException.ThrowIfNull(webhookEvent);

        switch (webhookEvent.Type)
        {
            case WebhookEventType.ChargeSucceeded:
                await _repository.UpdateTransactionStatusAsync(webhookEvent.ChargeId, TransactionStatus.Charged);
                break;
            case WebhookEventType.ChargeFailed:
                await _repository.UpdateTransactionStatusAsync(webhookEvent.ChargeId, TransactionStatus.Failed);
                break;
            case WebhookEventType.RefundCompleted:
                await _repository.UpdateTransactionStatusAsync(webhookEvent.ChargeId, TransactionStatus.Refunded);
                break;
            default:
                throw new ArgumentOutOfRangeException(nameof(webhookEvent), $"Unknown webhook event type: {webhookEvent.Type}");
        }
    }
}

// --- Models ---

public record ChargeResult(string ChargeId, bool Success);
public record RefundResult(string RefundId, bool Success);
public record ProcessorChargeResponse(string ChargeId, bool Succeeded);
public record ProcessorRefundResponse(string RefundId, bool Succeeded);

public record Transaction(
    string ChargeId,
    string CardToken,
    decimal Amount,
    TransactionStatus Status,
    DateTime CreatedUtc);

public record WebhookEvent(WebhookEventType Type, string ChargeId);

public enum TransactionStatus { Pending, Charged, Failed, Refunded }
public enum WebhookEventType { ChargeSucceeded, ChargeFailed, RefundCompleted }

